ba1_questions = [
  ("ba100000-0001-0001-0000-000000000001","ba100000-0001-0001-0000-000000000000","mcq",1,"A price BELOW equilibrium results in:","Excess demand — price rises to restore equilibrium",'["Excess supply — firms reduce prices","Excess demand — price rises to restore equilibrium","Equilibrium is maintained automatically","The demand curve shifts leftward"]',"Below equilibrium price, quantity demanded exceeds quantity supplied (shortage). Competition among buyers pushes price up until equilibrium is restored."),
  ("ba100000-0001-0001-0000-000000000002","ba100000-0001-0001-0000-000000000000","true_false",2,"A rise in the price of a substitute good will INCREASE the demand for a product.","True",None,"If a substitute becomes more expensive, consumers switch to the cheaper alternative, increasing its demand and shifting the demand curve to the right."),
  ("ba100000-0001-0001-0000-000000000003","ba100000-0001-0001-0000-000000000000","mcq",3,"Given Qd = 80 - 4P and Qs = 8 + 4P, what is the equilibrium price?","£9",'["£9","£8","£7","£10"]',"Set Qd = Qs: 80 - 4P = 8 + 4P. 72 = 8P. P = £9. Check: Qd = 44 = Qs. Confirmed."),
  ("ba100000-0001-0001-0000-000000000004","ba100000-0001-0001-0000-000000000000","mcq",4,"Which of the following would shift the supply curve to the RIGHT?","A technological improvement reducing production costs",'["An increase in raw material costs","Introduction of a new tax on the product","A technological improvement reducing production costs","A fall in the number of producers"]',"Lower production costs increase profitability, encouraging more supply at every price — shifting the supply curve rightward."),
  ("ba100000-0001-0002-0000-000000000001","ba100000-0001-0002-0000-000000000000","mcq",1,"A product has a PED of -2.5. If price is increased by 10%, total revenue will:","Decrease, because demand is elastic",'["Increase, because demand is inelastic","Decrease, because demand is elastic","Stay the same, because PED = -2.5","Increase, because PED is negative"]',"|PED| = 2.5 > 1, so demand is elastic. A 10% price rise causes a 25% fall in quantity. Revenue falls when demand is elastic."),
  ("ba100000-0001-0002-0000-000000000002","ba100000-0001-0002-0000-000000000000","mcq",2,"If price rises from £50 to £60 and quantity demanded falls from 400 to 360 units, what is the PED?","-0.5",'["-0.5","-2.0","-0.25","-4.0"]',"%changeQd = -10%. %changeP = +20%. PED = -10%/20% = -0.5. |PED| < 1 means inelastic."),
  ("ba100000-0001-0002-0000-000000000003","ba100000-0001-0002-0000-000000000000","true_false",3,"A luxury good has a YED greater than 1.","True",None,"Luxury goods are income elastic (YED > 1): as income rises, demand rises proportionally more. Examples: designer clothing, fine dining."),
  ("ba100000-0001-0002-0000-000000000004","ba100000-0001-0002-0000-000000000000","mcq",4,"Which factor is most likely to make supply INELASTIC in the short run?","Perishable or time-specific output",'["Abundant spare production capacity","Short production lead times","Perishable or time-specific output","Easy availability of substitute inputs"]',"Perishable goods cannot be stored and must be sold regardless of price — making supply inelastic. Spare capacity and short lead times increase elasticity."),
  ("ba100000-0001-0003-0000-000000000001","ba100000-0001-0003-0000-000000000000","mcq",1,"In perfect competition, a firm earns only normal profit in the long run because:","Free entry and exit eliminates supernormal profit",'["The government regulates prices","Free entry and exit eliminates supernormal profit","Firms collude to keep prices stable","Products are highly differentiated"]',"Supernormal profit attracts new entrants. Increased supply drives down price until only normal profit remains."),
  ("ba100000-0001-0003-0000-000000000002","ba100000-0001-0003-0000-000000000000","mcq",2,"A monopolist wishing to maximise profit will produce where:","Marginal revenue equals marginal cost",'["Price equals average cost","Marginal revenue equals marginal cost","Total revenue is maximised","Price equals marginal cost"]',"All profit-maximising firms produce where MR = MC, regardless of market structure."),
  ("ba100000-0001-0003-0000-000000000003","ba100000-0001-0003-0000-000000000000","true_false",3,"Price discrimination allows a monopolist to capture more consumer surplus.","True",None,"Price discrimination charges different prices based on willingness to pay, converting consumer surplus into producer surplus (profit)."),
  ("ba100000-0001-0003-0000-000000000004","ba100000-0001-0003-0000-000000000000","mcq",4,"Which market structure is characterised by a small number of large interdependent firms?","Oligopoly",'["Perfect competition","Monopolistic competition","Oligopoly","Monopsony"]',"Oligopoly features a small number of dominant firms. Interdependence means each firm's actions affect rivals, leading to strategic behaviour."),
  ("ba100000-0002-0001-0000-000000000001","ba100000-0002-0001-0000-000000000000","mcq",1,"Which formula correctly represents the expenditure approach to GDP?","GDP = C + I + G + (X - M)",'["GDP = C + S + G + (X - M)","GDP = C + I + G + (X - M)","GDP = W + P + R + I","GDP = C + I - G + (X + M)"]',"Expenditure approach: C (consumption) + I (investment) + G (government spending) + net exports (X - M). Imports are subtracted because they represent spending on foreign output."),
  ("ba100000-0002-0001-0000-000000000002","ba100000-0002-0001-0000-000000000000","mcq",2,"If the MPC is 0.75, what is the value of the Keynesian multiplier?","4",'["3","4","0.25","1.75"]',"Multiplier = 1 / (1 - MPC) = 1 / 0.25 = 4. A £1 billion increase in government spending increases national income by £4 billion."),
  ("ba100000-0002-0001-0000-000000000003","ba100000-0002-0001-0000-000000000000","true_false",3,"A recession is technically defined as two consecutive quarters of negative real GDP growth.","True",None,"This is the standard technical definition. It refers to REAL GDP growth (adjusted for inflation)."),
  ("ba100000-0002-0001-0000-000000000004","ba100000-0002-0001-0000-000000000000","mcq",4,"Which of the following is an INJECTION into the circular flow of income?","Investment spending by firms",'["Savings by households","Income tax paid to government","Imports of goods","Investment spending by firms"]',"Injections add money into the circular flow: Investment (I), Government spending (G), and Exports (X). Withdrawals: Savings (S), Taxation (T), Imports (M)."),
  ("ba100000-0002-0002-0000-000000000001","ba100000-0002-0002-0000-000000000000","mcq",1,"A sharp rise in world oil prices causing domestic inflation is an example of:","Cost-push inflation",'["Demand-pull inflation","Cost-push inflation","Hyperinflation","Structural inflation"]',"Rising input costs (oil, raw materials) push up production costs. These are passed on as higher prices — cost-push inflation."),
  ("ba100000-0002-0002-0000-000000000002","ba100000-0002-0002-0000-000000000000","mcq",2,"A worker who left their job to look for a better one is experiencing which type of unemployment?","Frictional unemployment",'["Structural unemployment","Cyclical unemployment","Frictional unemployment","Seasonal unemployment"]',"Frictional unemployment is temporary unemployment when moving between jobs. It exists even in a healthy economy and is part of the natural rate."),
  ("ba100000-0002-0002-0000-000000000003","ba100000-0002-0002-0000-000000000000","true_false",3,"Inflation benefits debtors at the expense of creditors.","True",None,"Inflation erodes the real value of money. Debtors repay loans with money worth less in real terms — a gain. Creditors receive back less in real terms — a loss."),
  ("ba100000-0002-0002-0000-000000000004","ba100000-0002-0002-0000-000000000000","mcq",4,"The long-run Phillips Curve is vertical because:","In the long run, inflation expectations adjust, eliminating the trade-off",'["Unemployment cannot be reduced below zero","In the long run, inflation expectations adjust, eliminating the trade-off","Governments always choose zero inflation","The central bank targets unemployment rather than inflation"]',"In the long run, workers and firms adjust their expectations. The economy returns to the natural rate regardless of the inflation rate."),
  ("ba100000-0002-0003-0000-000000000001","ba100000-0002-0003-0000-000000000000","mcq",1,"The Bank of England raises interest rates. This is an example of:","Contractionary monetary policy",'["Expansionary fiscal policy","Contractionary monetary policy","Expansionary monetary policy","Contractionary fiscal policy"]',"Raising interest rates is contractionary monetary policy — controlled by the central bank, not the government."),
  ("ba100000-0002-0003-0000-000000000002","ba100000-0002-0003-0000-000000000000","mcq",2,"Which of the following is an AUTOMATIC STABILISER?","Unemployment benefits that rise during a recession",'["A new infrastructure project announced in the budget","Unemployment benefits that rise during a recession","The Bank of England cutting interest rates","A government decision to cut income tax"]',"Automatic stabilisers work without deliberate policy decisions. Unemployment benefits automatically rise during a recession, cushioning the fall in aggregate demand."),
  ("ba100000-0002-0003-0000-000000000003","ba100000-0002-0003-0000-000000000000","true_false",3,"Quantitative Easing involves the central bank creating new money to purchase financial assets.","True",None,"QE: the central bank electronically creates money and uses it to buy government bonds and other assets from financial institutions, increasing the money supply."),
  ("ba100000-0002-0003-0000-000000000004","ba100000-0002-0003-0000-000000000000","mcq",4,"Supply-side policies differ from demand-side policies in that they aim to:","Increase the productive capacity and long-run potential of the economy",'["Increase aggregate demand directly","Increase the productive capacity and long-run potential of the economy","Reduce the budget deficit in the short term","Control the money supply"]',"Supply-side policies shift the aggregate supply curve outward, increasing potential GDP and enabling non-inflationary growth."),
  ("ba100000-0003-0001-0000-000000000001","ba100000-0003-0001-0000-000000000000","mcq",1,"If sterling appreciates against the dollar, which of the following is most likely?","UK exports become more expensive for US buyers",'["UK exports become cheaper for US buyers","UK inflation rises due to higher import prices","UK exports become more expensive for US buyers","The current account deficit narrows"]',"Appreciation means £1 buys more dollars. A UK product priced at £100 now costs more dollars — making UK exports less competitive."),
  ("ba100000-0003-0001-0000-000000000002","ba100000-0003-0001-0000-000000000000","mcq",2,"Country A: 10 cars or 20 tonnes of wheat per day. Country B: 8 cars or 24 tonnes of wheat. Who has comparative advantage in wheat?","Country B — its opportunity cost of wheat is lower",'["Country A — it produces more cars","Country B — its opportunity cost of wheat is lower","Country A — it produces more wheat","Neither — comparative advantage only applies to absolute producers"]',"Country A: 1 tonne wheat costs 0.5 cars. Country B: 1 tonne wheat costs 0.33 cars. Country B has lower opportunity cost in wheat."),
  ("ba100000-0003-0001-0000-000000000003","ba100000-0003-0001-0000-000000000000","true_false",3,"The J-curve effect suggests that a currency depreciation initially worsens the current account before it improves.","True",None,"Initially, existing trade contracts mean import volumes do not fall immediately. Import costs rise in domestic currency, worsening the current account. Over time volumes adjust and the current account improves."),
  ("ba100000-0003-0001-0000-000000000004","ba100000-0003-0001-0000-000000000000","mcq",4,"A tariff on imported steel is an example of:","A protectionist measure to reduce import competition",'["A supply-side policy to boost productivity","A protectionist measure to reduce import competition","An automatic stabiliser","A monetary policy tool"]',"A tariff is a tax on imports that raises the price of imported goods, making domestic producers more competitive."),
]

